#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it); K = next(it)
        arr = [next(it) for _ in range(N)]
        arr.sort()
        best = 10**18
        for i in range(N - K + 1):
            diff = arr[i+K-1] - arr[i]
            if diff < best:
                best = diff
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

